CREATE ALGORITHM=UNDEFINED DEFINER=`neolab`@`%` SQL SECURITY DEFINER VIEW `v_sku_event_features_12m` AS select `hv`.`SKU` AS `SKU`,count(0) AS `eventos_12m`,round(avg(`hv`.`Qty`),6) AS `q_evento_12m`,round(std(`hv`.`Qty`),6) AS `sigma_q_evento_12m`,round(avg(`hv`.`Margin_USD`),6) AS `margen_prom_evento_12m`,round(sum(`hv`.`Margin_USD`),6) AS `margen_total_12m`,round(avg(`hv`.`Revenue_USD`),6) AS `revenue_prom_evento_12m` from `v_hist_eventos_12m` `hv` group by `hv`.`SKU`